#include <iostream>\n#include <vector>\n#include <limits>\n\nstruct Edge {\n  Edge() = default;\n  Edge(int p_from, int p_to, int p_weight) : from(p_from), to(p_to), weight(p_weight) {\n  }\n\n  int from;\n  int to;\n  int weight;\n};\n\nclass Graph {\n public:\n  Graph(int n, const std::vector<Edge>& edges) {\n    dist_.resize(n, kInf);\n    Build(edges);\n  }\n\n  const std::vector<int>& GetDist() {\n    return dist_;\n  }\n\n private:\n  void Build(const std::vector<Edge>& edges) {\n    int n = static_cast<int>(dist_.size());\n    dist_[0] = 0;\n    for (int i = 0; i < n; i++) {\n      bool changed = false;\n      for (const Edge& edge : edges) {\n        int from = edge.from - 1;\n        int to = edge.to - 1;\n        int weight = edge.weight;\n        if (dist_[from] + weight < dist_[to] && dist_[from] != kInf) {\n          dist_[to] = dist_[from] + weight;\n          changed = true;\n        }\n      }\n      if (!changed) {\n        break;\n      }\n    }\n    for (int i = 0; i < n; i++) {\n      if (dist_[i] == kInf) {\n        dist_[i] = 30'000;\n      }\n    }\n  }\n\n  static constexpr int kInf = std::numeric_limits<int>::max();\n  std::vector<int> dist_;\n};\n\nint main() {\n  int n = 0;\n  int m = 0;\n  std::cin >> n >> m;\n  std::vector<Edge> edges(m);\n\n  for (int i = 0; i < m; i++) {\n    std::cin >> edges[i].from >> edges[i].to >> edges[i].weight;\n  }\n\n  Graph g(n, edges);\n\n  for (auto i : g.GetDist()) {\n    std::cout << i << ' ';\n  }\n  std::cout << std::endl;\n\n  return 0;\n}